:root {
  --background: light-dark(
    oklch(100% 0.00011 271.152),
    oklch(18.22% 0.00002 271.152)
  );
  --foreground: light-dark(
    oklch(18.22% 0.00002 271.152),
    oklch(98.511% 0.00011 271.152)
  );
}

html {
  color-scheme: light dark;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: sans-serif;
  background: var(--background);
  color: var(--foreground);
  overflow-x: hidden;
  max-width: 80rem;
  width: 100%;
  margin: 0 auto;
  padding: 0 1.25rem;
}

a {
  text-decoration: none;
  color: inherit;
}

.project-gallery {
  display: block;
}

/* Gallery items */
.gallery-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 6rem;
  border-top: 1px solid var(--foreground);
  cursor: pointer;
  transition: opacity 0.2s linear;
}

.gallery-item:hover {
  opacity: 0.4;
}

.gallery-item h2 {
  font-size: 3.75rem;
  font-weight: 400;
  transition: transform 0.2s linear;
}

.gallery-item p {
  transition: transform 0.2s linear;
}

.gallery-item:hover h2 {
  transform: translateX(-12px);
}

.gallery-item:hover p {
  transform: translateX(12px);
}

/* Modal and cursor */
.modal,
.cursor,
.cursor-label {
  position: fixed;
  pointer-events: none;
  transform: translate(-50%, -50%) scale(0);
  z-index: 1000;
  will-change: transform, left, top;
  transform-origin: center center;
}

.modal {
  width: 400px;
  height: 350px;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
}

.modal-images {
  position: absolute;
  width: 100%;
  transition: top 0.5s cubic-bezier(0.76, 0, 0.24, 1);
}

.modal-image {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  height: 350px;
}

.modal-image img {
  width: 350px;
  height: auto;
}

.cursor,
.cursor-label {
  width: 80px;
  height: 80px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
}

.cursor {
  background: #2563eb;
}

.cursor-label {
  color: white;
  font-size: 16px;
}

/* Project image for mobile */
.project-image-container {
  display: none;
}

/* Responsive styles */
@media (max-width: 768px) {
  .project-gallery {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .gallery-item {
    flex-direction: column;
    align-items: flex-start;
    padding: 1rem;
    border-top: none;
    width: 100%;
    transition: none;
  }

  .project-image-container {
    display: block;
    position: relative;
    width: 100%;
    overflow: hidden;
    aspect-ratio: 4 / 3;
    margin-bottom: 1rem;
  }

  .project-image-container img {
    width: 100%;
    height: 100%;
    object-fit: contain;
    padding: 1rem;
    aspect-ratio: 4 / 3;
  }

  .gallery-item h2 {
    font-size: 1.5rem;
    font-weight: 700;
    line-height: 2rem;
  }

  .gallery-item p {
    font-size: 0.875rem;
    font-weight: 300;
    line-height: 1.25rem;
  }

  .gallery-item:hover {
    opacity: 1;
  }

  .gallery-item:hover h2,
  .gallery-item:hover p {
    transform: none;
  }

  .modal,
  .cursor,
  .cursor-label {
    display: none !important;
  }
}

@media (min-width: 640px) and (max-width: 768px) {
  .project-gallery {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .gallery-item h2 {
    font-size: 1.875rem;
    line-height: 2.25rem;
  }
}

@media (max-width: 640px) {
  .project-gallery {
    grid-template-columns: repeat(1, minmax(0, 1fr));
  }
}

import { animate as motionAnimate } from "motion";

const gallery = document.getElementById("project-gallery");
const galleryItems = gallery.querySelectorAll(".gallery-item");

function createInteractiveElements() {
  // Create Modal
  const section = document.createElement("section");
  section.id = "interactive-modal";
  section.className = "interactive-modal";

  const modal = document.createElement("div");
  modal.className = "modal";
  modal.id = "modal";

  const modalImages = document.createElement("div");
  modalImages.className = "modal-images";
  modalImages.id = "modal-images";

  galleryItems.forEach((item) => {
    const container = item.querySelector(".project-image-container");
    const img = container.querySelector("img");

    const modalImageDiv = document.createElement("div");
    modalImageDiv.className = "modal-image";
    modalImageDiv.style.backgroundColor = container.style.backgroundColor || "";

    const modalImg = document.createElement("img");
    modalImg.src = img.src;
    modalImg.alt = img.alt;

    modalImageDiv.appendChild(modalImg);
    modalImages.appendChild(modalImageDiv);
  });

  modal.appendChild(modalImages);
  section.appendChild(modal);

  // Create Cursor
  const cursor = document.createElement("div");
  cursor.className = "cursor";
  cursor.id = "cursor";

  const cursorLabel = document.createElement("div");
  cursorLabel.className = "cursor-label";
  cursorLabel.id = "cursor-label";
  cursorLabel.textContent = "View";

  section.appendChild(cursor);
  section.appendChild(cursorLabel);

  // Insert after the gallery section
  gallery.after(section);

  return { modal, modalImages, cursor, cursorLabel };
}

const { modal, modalImages, cursor, cursorLabel } = createInteractiveElements();

// State
let activeIndex = 0;
let isModalVisible = false;
let mouseX = 0;
let mouseY = 0;

// Animation options
const modalAnimationOptions = {
  duration: 300,
  easing: "ease-out",
  fill: "forwards",
};

const cursorAnimationOptions = {
  duration: 150,
  easing: "ease-out",
  fill: "forwards",
};

// Helpers
function isMobile() {
  return window.innerWidth <= 768;
}

// Animation loop for smooth following
function updatePositions() {
  if (isModalVisible) {
    const modalWidth = modal.offsetWidth;
    const modalHeight = modal.offsetHeight;
    const cursorWidth = cursor.offsetWidth;
    const cursorHeight = cursor.offsetHeight;

    const modalLeft = mouseX - modalWidth / 2;
    const modalTop = mouseY - modalHeight / 2;
    const cursorLeft = mouseX - cursorWidth / 2;
    const cursorTop = mouseY - cursorHeight / 2;

    modal.animate(
      [
        { left: modal.offsetLeft + "px", top: modal.offsetTop + "px" },
        { left: modalLeft + "px", top: modalTop + "px" },
      ],
      modalAnimationOptions,
    );

    modal.style.left = modalLeft + "px";
    modal.style.top = modalTop + "px";

    cursor.animate(
      [
        { left: cursor.offsetLeft + "px", top: cursor.offsetTop + "px" },
        { left: cursorLeft + "px", top: cursorTop + "px" },
      ],
      cursorAnimationOptions,
    );

    cursor.style.left = cursorLeft + "px";
    cursor.style.top = cursorTop + "px";

    cursorLabel.animate(
      [
        {
          left: cursorLabel.offsetLeft + "px",
          top: cursorLabel.offsetTop + "px",
        },
        { left: cursorLeft + "px", top: cursorTop + "px" },
      ],
      cursorAnimationOptions,
    );

    cursorLabel.style.left = cursorLeft + "px";
    cursorLabel.style.top = cursorTop + "px";
  }

  requestAnimationFrame(updatePositions);
}

// Mouse tracking
function handleMouseMove(e) {
  mouseX = e.clientX;
  mouseY = e.clientY;
}

// Modal show / hide
function showModal(index) {
  if (isMobile()) return;

  if (index < 0 || index >= galleryItems.length) {
    console.error(`Invalid project index: ${index}`);
    return;
  }

  activeIndex = index;
  modalImages.style.top = `-${index * 100}%`;
  isModalVisible = true;

  motionAnimate(modal, {
    scale: 1,
    transition: {
      duration: 0.4,
      ease: [0.76, 0, 0.24, 1],
    },
  });

  motionAnimate(cursor, {
    scale: 1,
    transition: {
      duration: 0.4,
      ease: [0.76, 0, 0.24, 1],
    },
  });

  motionAnimate(cursorLabel, {
    scale: 1,
    transition: {
      duration: 0.4,
      ease: [0.76, 0, 0.24, 1],
    },
  });
}

function hideModal() {
  if (isMobile()) return;

  isModalVisible = false;

  motionAnimate(modal, {
    scale: 0,
    transition: {
      duration: 0.4,
      ease: [0.32, 0, 0.67, 0],
    },
  });

  motionAnimate(cursor, {
    scale: 0,
    transition: {
      duration: 0.4,
      ease: [0.32, 0, 0.67, 0],
    },
  });

  motionAnimate(cursorLabel, {
    scale: 0,
    transition: {
      duration: 0.4,
      ease: [0.32, 0, 0.67, 0],
    },
  });
}

// Event listeners
galleryItems.forEach((item, index) => {
  item.addEventListener("mouseenter", (e) => {
    e.preventDefault();
    showModal(index);
  });

  item.addEventListener("mouseleave", hideModal);
});

window.addEventListener("mousemove", handleMouseMove);

// Start the animation loop
updatePositions();
